import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

const PALETTE = {
  CLEMENTINA: "#FF4201",
  SKYNE: "#199ECA",
  IVRAE: "#F6EEE3",
  NEGRO: "#000000",
  VERDE: "#166D3B",
  VERDE_BAJO: "#2f7a2b", // Verde menos intenso para botón activo
  WHITE: "#FFFFFF",
  INPUT_BORDER: "#D0D0D0",
  SHADOW_CONTOUR_COLOR: "rgba(0, 0, 0, 0.4)",
};

const ICON_SVG_SIZE = "50px"; // Icono un poco más grande
const ICON_CONTAINER_PADDING = "12px";

const UserIcon = ({ color, size = ICON_SVG_SIZE }) => (
  <svg
    viewBox="0 0 24 24"
    style={{ width: size, height: size, fill: color, display: "block" }}
  >
    <path d="M12 12c2.76 0 5-2.24 5-5S14.76 2 12 2 7 4.24 7 7s2.24 5 5 5zm0 2c-3.33 0-10 1.67-10 5v3h20v-3c0-3.33-6.67-5-10-5z" />
  </svg>
);

const InicioSesion = ({ onLogin, onClose }) => {
  const [usuario, setUsuario] = useState("");
  const [contrasenia, setContrasenia] = useState("");
  const [loading, setLoading] = useState(false);
  const [mensaje, setMensaje] = useState(null);
  const [isVisible, setIsVisible] = useState(true);

  const inputVariants = {
    focus: {
      scale: 1.02,
      boxShadow: `0 0 0 2px ${PALETTE.CLEMENTINA}`,
      transition: { duration: 0.3 },
    },
  };
  const buttonVariants = {
    hover: { scale: 1.05, transition: { duration: 0.2 } },
    tap: { backgroundColor: PALETTE.VERDE_BAJO }, // Verde más bajo al presionar
  };

  const backdropVariants = {
    hidden: { opacity: 0 },
    visible: { opacity: 1, transition: { duration: 0.3 } },
    exit: { opacity: 0, transition: { duration: 0.3 } },
  };
  const modalVariants = {
    hidden: { y: -50, opacity: 0 },
    visible: {
      y: 0,
      opacity: 1,
      transition: { type: "spring", stiffness: 120, damping: 20 },
    },
    exit: { y: -50, opacity: 0, transition: { duration: 0.3 } },
  };
  const iconVariants = {
    hidden: { scale: 0 },
    visible: {
      scale: 1,
      transition: { delay: 0.4, type: "spring", stiffness: 150 },
    },
    exit: { scale: 0, transition: { duration: 0.2 } },
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMensaje(null);

    if (!usuario || !contrasenia) {
      setMensaje("Por favor, rellena todos los campos");
      return;
    }

    setLoading(true);
    try {
      const res = await fetch("http://localhost:3000/usuarios/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ usuario, contrasenia }),
      });
      const data = await res.json();

      if (res.ok && data.encontrado === 1) {
        setMensaje("Iniciaste sesión correctamente");
        onLogin(data.usuario);
        setTimeout(() => {
          setIsVisible(false);
          if (onClose) onClose();
        }, 1500);
      } else {
        setMensaje(data.mensaje || "Credenciales incorrectas");
      }
    } catch {
      setMensaje("Error de conexión con el servidor");
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => {
    setIsVisible(false);
    if (onClose) onClose();
  };

  const inputBaseStyle = {
    width: "100%",
    padding: "14px 18px", // un poco más grande
    fontSize: "20px", // letra más grande para inputs
    border: `1.8px solid ${PALETTE.INPUT_BORDER}`, // borde un poco más grueso
    borderRadius: "12px", // bordes más redondos
    backgroundColor: PALETTE.WHITE,
    marginBottom: "20px",
    textAlign: "center",
    color: PALETTE.NEGRO,
    fontFamily: "'Caveat', cursive",
    boxSizing: "border-box",
  };

  const labelStyle = {
    fontFamily: "'Caveat', cursive",
    fontWeight: "700",
    fontSize: "20px",
    marginBottom: "6px",
    color: PALETTE.NEGRO,
    userSelect: "none",
  };

  const iconContainerStyle = {
    position: "absolute",
    top: "-38px", // más alto para icono más grande
    left: "44%",
    transform: "translateX(-50%)",
    backgroundColor: PALETTE.IVRAE,
    borderRadius: "50%",
    padding: ICON_CONTAINER_PADDING,
    boxShadow: "0px -3px 6px rgba(0, 0, 0, 0.1)",
    zIndex: 1,
  };

  const modalStyle = {
    position: "relative",
    backgroundColor: PALETTE.IVRAE,
    borderRadius: "30px", // un poco más grande y redondeado
    width: "520px", // más ancho
    padding: "50px 40px 40px",
    textAlign: "center",
    fontFamily: "'Poppins', sans-serif",
    boxShadow: `0 0 0 12px ${PALETTE.SHADOW_CONTOUR_COLOR}`,
  };

  const mensajeStyle = {
    marginBottom: "16px",
    fontWeight: "bold",
    color:
      mensaje === "Iniciaste sesión correctamente"
        ? PALETTE.VERDE
        : PALETTE.CLEMENTINA,
    fontFamily: "'Caveat', cursive",
    fontSize: "18px",
  };

  return (
    <AnimatePresence onExitComplete={handleClose}>
      {isVisible && (
        <motion.div
          key="backdrop"
          variants={backdropVariants}
          initial="hidden"
          animate="visible"
          exit="exit"
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            width: "100vw",
            height: "100vh",
            backgroundColor: "rgba(0,0,0,0.65)",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            zIndex: 9999,
          }}
        >
          <motion.div
            key="modal"
            variants={modalVariants}
            initial="hidden"
            animate="visible"
            exit="exit"
            style={modalStyle}
          >
            <motion.div
              variants={iconVariants}
              initial="hidden"
              animate="visible"
              exit="exit"
              style={iconContainerStyle}
            >
              <UserIcon color={PALETTE.NEGRO} />
            </motion.div>

            <motion.button
              onClick={handleClose}
              whileHover={{ scale: 1.2 }}
              style={{
                position: "absolute",
                top: "8px",
                right: "20px",
                background: "none",
                border: "none",
                fontSize: "45px",
                cursor: "pointer",
                color: PALETTE.NEGRO,
                lineHeight: 1,
                padding: 0,
              }}
            >
              &times;
            </motion.button>

            <h2
              style={{
                margin: "15px 0",
                fontSize: "20px",
                fontWeight: 700,
                color: PALETTE.NEGRO,
                textTransform: "uppercase",
                letterSpacing: "1px",
                fontFamily: "'Caveat', cursive",
                userSelect: "none",
              }}
            >
              Inicio de Sesión
            </h2>

            {mensaje && <p style={mensajeStyle}>{mensaje}</p>}

            <form onSubmit={handleSubmit}>
              <label htmlFor="usuario" style={labelStyle}>
             
              </label>
              <motion.input
                id="usuario"
                type="text"
                placeholder="Escribe tu usuario"
                value={usuario}
                onChange={(e) => setUsuario(e.target.value)}
                variants={inputVariants}
                whileFocus="focus"
                style={inputBaseStyle}
              />

              <label htmlFor="contrasenia" style={labelStyle}>
              
              </label>
              <motion.input
                id="contrasenia"
                type="password"
                placeholder="Escribe tu contraseña"
                value={contrasenia}
                onChange={(e) => setContrasenia(e.target.value)}
                variants={inputVariants}
                whileFocus="focus"
                style={inputBaseStyle}
              />

              <motion.button
                type="submit"
                disabled={loading}
                variants={buttonVariants}
                whileHover="hover"
                whileTap="tap"
                style={{
                  width: "100%",
                  padding: "14px",
                  fontSize: "18px",
                  fontWeight: 700,
                  border: "none",
                  borderRadius: "12px",
                  backgroundColor: PALETTE.VERDE,
                  color: PALETTE.WHITE,
                  cursor: loading ? "not-allowed" : "pointer",
                  textTransform: "uppercase",
                  opacity: loading ? 0.7 : 1,
                  fontFamily: "'Caveat', cursive",
                }}
              >
                {loading ? "Iniciando..." : "Enviar"}
              </motion.button>
            </form>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

export default InicioSesion;
